module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] partial_products [7:0];
    reg [3:0] shift_count;
    reg [7:0] multiplier;
    reg [15:0] result;
    reg [3:0] i;

    always @(*) begin
        multiplier = B;
        shift_count = 0;
        result = 0;

        for (i = 0; i < 8; i = i + 1) begin
            if (multiplier[0] == 1'b1) begin
                partial_products[i] = A << shift_count;
            end else begin
                partial_products[i] = 16'b0;
            end
            shift_count = shift_count + 1;
            multiplier = multiplier >> 1;
        end

        for (i = 0; i < 8; i = i + 1) begin
            result = result + partial_products[i];
        end

        product = result;
    end

endmodule
